package main

import (
	"fmt"
	"net/http"
	"strconv"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	// Define a counter for user requests with labels for user and request type
	userRequestCounter = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "user_requests_total",
			Help: "Total number of requests per user",
		},
		[]string{"user", "request_type"},
	)
)

func init() {
	// Register the metrics with Prometheus
	prometheus.MustRegister(userRequestCounter)
}

func main() {
	http.Handle("/metrics", promhttp.Handler())
	http.HandleFunc("/track", trackUserRequest)

	fmt.Println("Starting server on :8080")
	http.ListenAndServe(":8080", nil)
}

func trackUserRequest(w http.ResponseWriter, r *http.Request) {
	user := r.URL.Query().Get("user")
	requestType := r.URL.Query().Get("request_type")

	if user == "" || requestType == "" {
		http.Error(w, "Missing user or request_type parameter", http.StatusBadRequest)
		return
	}

	// Increment the user request counter
	userRequestCounter.WithLabelValues(user, requestType).Inc()

	fmt.Fprintf(w, "Tracked request for user: %s, type: %s\n", user, requestType)
}